106	// ReviewSession is the server-side review state machine persisted under
107	// .ddx/reviews/<session-id>/ for Story 16 and review mutations.
108	//
109	// Story 16 on-disk contract:
110	//   - manifest.json stores the session metadata only: id, artifact refs,
111	//     rubric/template/prompt refs, status, and billing limits.
112	//   - turns.jsonl is append-only JSONL. Each non-empty line is one ReviewTurn
113	//     record with actor, content, cost_usd, and created_at.
114	//   - attachments/ stores any binary sidecar files for the session.
115	//
116	// The manifest is written when a session is created. Turns are appended
117	// without rewriting prior lines so the review transcript remains durable and
118	// streamable.
119	type ReviewSession struct {
120		ID             string       `json:"id"`
121		ArtifactID     string       `json:"artifact_id"`
122		ArtifactSHA    string       `json:"artifact_sha"`
123		ArtifactGitRev string       `json:"artifact_git_rev"`
124		SystemRubric   string       `json:"system_rubric"`
125		TemplateRef    string       `json:"template_ref"`
126		PromptRef      string       `json:"prompt_ref"`
127		Status         string       `json:"status"`
128		Turns          []ReviewTurn `json:"turns,omitempty"`
129		CostUSD        float64      `json:"cost_usd"`
130		MaxBillableUSD float64      `json:"max_billable_usd"`
131	}
