165	// Create initializes the session directory, writes manifest.json, seeds
166	// turns.jsonl, and creates attachments/.
167	func (s *ReviewSessionStore) Create(session ReviewSession) error {
168		if s == nil {
169			return errors.New("review session store: nil store")
170		}
171		root, err := s.sessionRoot(session.ID)
172		if err != nil {
173			return err
174		}
175	
176		s.mu.Lock()
177		defer s.mu.Unlock()
178	
179		if err := os.MkdirAll(filepath.Join(root, reviewAttachmentsDir), 0o755); err != nil {
180			return fmt.Errorf("review session: mkdir attachments: %w", err)
181		}
182		if err := writeJSONFile(filepath.Join(root, reviewManifestName), reviewSessionManifestFrom(session)); err != nil {
183			return err
184		}
185		if err := os.WriteFile(filepath.Join(root, reviewTurnsName), nil, 0o644); err != nil {
186			return fmt.Errorf("review session: seed turns: %w", err)
187		}
188		return nil
189	}
190	
191	// AppendTurn appends a single transcript entry to turns.jsonl. It enforces
192	// MaxBillableUSD: if the session has a non-zero budget cap and the accumulated
193	// cost plus this turn's cost would exceed it, AppendTurn returns a
194	// *ReviewCostCapExceededError without writing the turn. On success the
195	// manifest's CostUSD accumulator is updated to reflect the new total.
196	func (s *ReviewSessionStore) AppendTurn(sessionID string, turn ReviewTurn) error {
197		if s == nil {
198			return errors.New("review session store: nil store")
199		}
200		root, err := s.sessionRoot(sessionID)
201		if err != nil {
202			return err
203		}
204	
205		s.mu.Lock()
206		defer s.mu.Unlock()
207	
208		if err := os.MkdirAll(root, 0o755); err != nil {
209			return fmt.Errorf("review session: mkdir session: %w", err)
210		}
211	
212		// Load the manifest to check the cost cap and read the current accumulated
213		// cost. If the manifest does not exist yet (session created without Create),
214		// proceed without enforcement.
215		manifestPath := filepath.Join(root, reviewManifestName)
216		var manifest *reviewSessionManifest
217		if data, readErr := os.ReadFile(manifestPath); readErr == nil {
218			var m reviewSessionManifest
219			if jsonErr := json.Unmarshal(data, &m); jsonErr == nil {
220				manifest = &m
221			}
222		}
223	
224		if manifest != nil && manifest.MaxBillableUSD > 0 {
225			if manifest.CostUSD+turn.CostUSD > manifest.MaxBillableUSD {
226				return &ReviewCostCapExceededError{
227					SessionID:   sessionID,
228					CurrentCost: manifest.CostUSD,
229					TurnCost:    turn.CostUSD,
230					MaxUSD:      manifest.MaxBillableUSD,
231				}
232			}
233		}
234	
235		if turn.CreatedAt.IsZero() {
236			turn.CreatedAt = time.Now().UTC()
237		}
238		path := filepath.Join(root, reviewTurnsName)
239		f, err := os.OpenFile(path, os.O_APPEND|os.O_CREATE|os.O_WRONLY, 0o644)
240		if err != nil {
241			return fmt.Errorf("review session: open turns: %w", err)
242		}
243		defer f.Close()
244		if err := json.NewEncoder(f).Encode(turn); err != nil {
245			return fmt.Errorf("review session: encode turn: %w", err)
246		}
247	
248		// Update the manifest's CostUSD accumulator so the next AppendTurn sees
249		// the correct running total.
250		if manifest != nil {
251			manifest.CostUSD += turn.CostUSD
252			_ = writeJSONFile(manifestPath, *manifest)
253		}
254	
255		return nil
256	}
