157	func (s *inMemoryReviewSessionService) Cancel(_ context.Context, sessionID string) (bool, error) {
158		if sessionID == "" {
159			return false, fmt.Errorf("reviewSessionCancel: sessionId is required")
160		}
161	
162		s.mu.Lock()
163		defer s.mu.Unlock()
164		session, ok := s.sessions[sessionID]
165		if !ok {
166			return false, fmt.Errorf("reviewSessionCancel: session %q not found", sessionID)
167		}
168		session.Status = ReviewSessionStatusCancelled
169		return true, nil
170	}
