172	func (s *inMemoryReviewSessionService) Subscribe(sessionID string) (<-chan *ReviewSessionEvent, func()) {
173		ch := make(chan *ReviewSessionEvent, 16)
174		s.mu.Lock()
175		s.subs[sessionID] = append(s.subs[sessionID], ch)
176		s.mu.Unlock()
177	
178		unsub := func() {
179			s.mu.Lock()
180			defer s.mu.Unlock()
181			subs := s.subs[sessionID]
182			for i, c := range subs {
183				if c == ch {
184					s.subs[sessionID] = append(subs[:i], subs[i+1:]...)
185					close(ch)
186					return
187				}
188			}
189		}
190		return ch, unsub
191	}
192	
193	func (s *inMemoryReviewSessionService) publish(sessionID string, event *ReviewSessionEvent) {
194		s.mu.Lock()
195		subs := append([]chan *ReviewSessionEvent(nil), s.subs[sessionID]...)
196		s.mu.Unlock()
197		for _, ch := range subs {
198			select {
199			case ch <- event:
200			default:
201			}
202		}
203	}
