205	func cloneReviewSession(in *ReviewSession) *ReviewSession {
206		if in == nil {
207			return nil
208		}
209		out := *in
210		if in.Turns != nil {
211			out.Turns = make([]*ReviewTurn, len(in.Turns))
212			for i, t := range in.Turns {
213				tc := *t
214				out.Turns[i] = &tc
215			}
216		}
217		return &out
218	}
