220	func newReviewSessionID() (string, error) {
221		buf := make([]byte, 8)
222		if _, err := rand.Read(buf); err != nil {
223			return "", fmt.Errorf("review session id: %w", err)
224		}
225		return "rev-" + hex.EncodeToString(buf), nil
226	}
