228	// reviewSessionService returns the resolver's wired ReviewSessions service,
229	// lazily allocating the in-memory default when none was wired so the resolver
230	// is usable without external configuration.
231	func (r *Resolver) reviewSessionService() ReviewSessionService {
232		r.reviewMu.Lock()
233		defer r.reviewMu.Unlock()
234		if r.ReviewSessions == nil {
235			r.ReviewSessions = NewInMemoryReviewSessionService()
236		}
237		return r.ReviewSessions
238	}
