240	// ReviewSessionStart is the resolver for the reviewSessionStart mutation.
241	func (r *mutationResolver) ReviewSessionStart(ctx context.Context, input ReviewSessionStartInput) (*ReviewSession, error) {
242		return r.reviewSessionService().Start(ctx, input)
243	}
244	
245	// ReviewSessionRespond is the resolver for the reviewSessionRespond mutation.
246	func (r *mutationResolver) ReviewSessionRespond(ctx context.Context, sessionID string, turn ReviewTurnInput) (*ReviewSession, error) {
247		return r.reviewSessionService().Respond(ctx, sessionID, turn)
248	}
