// productionReviewSessionService implements ddxgraphql.ReviewSessionService
// using the on-disk ReviewSessionStore and ReviewDispatcher for production persistence.
type productionReviewSessionService struct {
	projectRoot string
	store       *ReviewSessionStore
	dispatcher  *ReviewDispatcher
	mu          sync.Mutex
	subs        map[string][]chan *ddxgraphql.ReviewSessionEvent
}

// NewProductionReviewSessionService wires the on-disk storage and dispatcher
// implementation. It dispatches review turns to the agent harness and persists
// all session state to disk under .ddx/reviews/.
func NewProductionReviewSessionService(projectRoot string) ddxgraphql.ReviewSessionService {
	return &productionReviewSessionService{
		projectRoot: projectRoot,
		store:       NewReviewSessionStore(projectRoot),
		dispatcher: &ReviewDispatcher{
			ProjectRoot: projectRoot,
		},
		subs: map[string][]chan *ddxgraphql.ReviewSessionEvent{},
	}
}

func (s *productionReviewSessionService) Start(ctx context.Context, input ddxgraphql.ReviewSessionStartInput) (*ddxgraphql.ReviewSession, error) {
	sessionID := ""
	if input.SessionID != nil {
		sessionID = *input.SessionID
	}
	if sessionID == "" {
		var err error
		sessionID, err = newReviewSessionID()
		if err != nil {
			return nil, err
		}
	}

	session := ReviewSession{
		ID:             sessionID,
		ArtifactID:     input.ArtifactID,
		ArtifactSHA:    input.ArtifactSha,
		ArtifactGitRev: input.ArtifactGitRev,
		SystemRubric:   input.SystemRubric,
		TemplateRef:    input.TemplateRef,
		PromptRef:      input.PromptRef,
		Status:         "active",
		Turns:          []ReviewTurn{},
	}
	if input.MaxBillableUsd != nil {
		session.MaxBillableUSD = *input.MaxBillableUsd
	}

	if err := s.store.Create(session); err != nil {
		return nil, err
	}

	s.dispatcher.Store = s.store
	return graphQLReviewSessionFromServer(session), nil
}

func (s *productionReviewSessionService) Respond(ctx context.Context, sessionID string, turn ddxgraphql.ReviewTurnInput) (*ddxgraphql.ReviewSession, error) {
	loaded, err := s.store.Load(sessionID)
	if err != nil {
		return nil, err
	}

	userTurn := ReviewTurn{
		Actor:     "user",
		Content:   turn.Content,
		CreatedAt: time.Now().UTC(),
	}
	if err := s.store.AppendTurn(sessionID, userTurn); err != nil {
		if costExceededErr, ok := err.(*ReviewCostCapExceededError); ok {
			s.publishRefusal(sessionID, &costExceededErr.RefusalBody())
			return loaded, err
		}
		if unavailableErr, ok := err.(*ReviewerUnavailableError); ok {
			body := unavailableErr.RefusalBody()
			s.publishRefusal(sessionID, &body)
			return loaded, err
		}
		return nil, err
	}

	s.dispatcher.Store = s.store
	reviewerTurn, dispatchErr := s.dispatcher.DispatchReviewTurn(ctx, *loaded, userTurn)
	if dispatchErr != nil {
		return nil, dispatchErr
	}

	updatedSession, err := s.store.Load(sessionID)
	if err != nil {
		return nil, err
	}

	s.publishEvent(sessionID, &ddxgraphql.ReviewSessionEvent{
		SessionID: sessionID,
		Kind:      ddxgraphql.ReviewSessionEventKindFinal,
		Content:   reviewerTurn.Content,
		CostUsd:   reviewerTurn.CostUSD,
		Timestamp: reviewerTurn.CreatedAt.Format(time.RFC3339Nano),
	})

	return graphQLReviewSessionFromServer(*updatedSession), nil
}

func (s *productionReviewSessionService) Cancel(ctx context.Context, sessionID string) (bool, error) {
	loaded, err := s.store.Load(sessionID)
	if err != nil {
		return false, err
	}
	loaded.Status = "cancelled"
	return true, nil
}

func (s *productionReviewSessionService) Subscribe(sessionID string) (<-chan *ddxgraphql.ReviewSessionEvent, func()) {
	ch := make(chan *ddxgraphql.ReviewSessionEvent, 16)
	s.mu.Lock()
	s.subs[sessionID] = append(s.subs[sessionID], ch)
	s.mu.Unlock()

	unsub := func() {
		s.mu.Lock()
		defer s.mu.Unlock()
		subs := s.subs[sessionID]
		for i, c := range subs {
			if c == ch {
				s.subs[sessionID] = append(subs[:i], subs[i+1:]...)
				close(ch)
				return
			}
		}
	}
	return ch, unsub
}

func (s *productionReviewSessionService) publishEvent(sessionID string, event *ddxgraphql.ReviewSessionEvent) {
	s.mu.Lock()
	subs := append([]chan *ddxgraphql.ReviewSessionEvent(nil), s.subs[sessionID]...)
	s.mu.Unlock()
	for _, ch := range subs {
		select {
		case ch <- event:
		default:
		}
	}
}

func (s *productionReviewSessionService) publishRefusal(sessionID string, refusal *ReviewRefusalBody) {
	refusalJSON, err := MarshalRefusalJSON(refusal.Code, refusal.Message, refusal.OperatorAction, refusal.Retryable)
	if err != nil {
		return
	}
	s.publishEvent(sessionID, &ddxgraphql.ReviewSessionEvent{
		SessionID: sessionID,
		Kind:      ddxgraphql.ReviewSessionEventKindFinal,
		Content:   refusalJSON,
		CostUsd:   0,
		Timestamp: time.Now().UTC().Format(time.RFC3339Nano),
	})
}

func graphQLReviewSessionFromServer(session ReviewSession) *ddxgraphql.ReviewSession {
	turns := make([]*ddxgraphql.ReviewTurn, len(session.Turns))
	for i, t := range session.Turns {
		turns[i] = &ddxgraphql.ReviewTurn{
			Actor:     t.Actor,
			Content:   t.Content,
			CostUsd:   t.CostUSD,
			CreatedAt: t.CreatedAt.Format(time.RFC3339Nano),
		}
	}
	return &ddxgraphql.ReviewSession{
		ID:             session.ID,
		ArtifactID:     session.ArtifactID,
		ArtifactSha:    session.ArtifactSHA,
		Status:         session.Status,
		Turns:          turns,
		CostUsd:        session.CostUSD,
		MaxBillableUsd: &session.MaxBillableUSD,
	}
}
